function getText() {
  if (message && message.contact && message.contact.phone_number) {
    return String(message.contact.phone_number);
  }
  if (message && message.text) {
    return String(message.text).trim();
  }
  return "";
}

function cleanupInternal() {
  delete_context("_job_apply_step");
}

function ask(prompt) {
  send_message({ text: prompt, parse_mode: "HTML" });
}

var steps = [
  {
    key: "job_apply_full_name",
    prompt: get_context("param_name_prompt") || "Vakansiya uchun ism va familiyangizni kiriting:",
    error: "Iltimos, to'liq ism kiriting.",
    validate: function(value) { return value.length >= 3; }
  },
  {
    key: "job_apply_role",
    prompt: get_context("param_role_prompt") || "Qaysi lavozimga topshirmoqchisiz?",
    error: "Lavozim nomini kiriting.",
    validate: function(value) { return value.length >= 2; }
  },
  {
    key: "job_apply_experience",
    prompt: get_context("param_experience_prompt") || "Qisqacha tajribangizni yozing:",
    error: "Kamida bir necha so'z yozing.",
    validate: function(value) { return value.length >= 5; }
  },
  {
    key: "job_apply_phone",
    prompt: get_context("param_phone_prompt") || "Bog'lanish uchun telefon raqamingizni yuboring:",
    error: "Telefon raqamini +998901234567 formatida kiriting yoki kontakt yuboring.",
    validate: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      return /^\+?\d{9,15}$/.test(cleaned);
    },
    normalize: function(value) {
      var cleaned = value.replace(/[^\d+]/g, "");
      if (cleaned[0] !== "+") return "+" + cleaned;
      return cleaned;
    }
  },
  {
    key: "job_apply_portfolio",
    prompt: get_context("param_portfolio_prompt") || "Portfolio, GitHub yoki CV linkini yuboring. Bo'lmasa '-' deb yuboring.",
    error: "Javobni qayta yuboring.",
    validate: function(value) { return value.length >= 1; },
    normalize: function(value) {
      if (value === "-") return "";
      return value;
    }
  }
];

var step = parseInt(get_context("_job_apply_step") || "0", 10);
var answer = getText();

if (answer.toLowerCase() === "/cancel") {
  cleanupInternal();
  exit("cancelled");
}

if (step > 0) {
  var previous = steps[step - 1];
  var value = answer;
  if (previous.normalize) value = previous.normalize(value);
  if (!previous.validate(value)) {
    ask(previous.error + "\n\nBekor qilish uchun /cancel yuboring.");
    wait_for_input();
  }
  set_context(previous.key, value);
}

if (step >= steps.length) {
  var successMessage = get_context("param_success_message") || (
    "<b>Arizangiz qabul qilindi.</b>\n\n" +
    "👤 Nomzod: " + (get_context("job_apply_full_name") || "") + "\n" +
    "💼 Lavozim: " + (get_context("job_apply_role") || "") + "\n" +
    "🧠 Tajriba: " + (get_context("job_apply_experience") || "") + "\n" +
    "📞 Telefon: " + (get_context("job_apply_phone") || "") + "\n" +
    "🔗 Portfolio/CV: " + (get_context("job_apply_portfolio") || "-")
  );
  send_message({ text: successMessage, parse_mode: "HTML" });
  cleanupInternal();
  exit("completed");
}

ask(steps[step].prompt + "\n\nBekor qilish uchun /cancel yuboring.");
set_context("_job_apply_step", String(step + 1));
wait_for_input();
